#!/bin/bash
set -e
cd /workspaces/Purgatoire
mkdir -p .github/workflows
python3 - << 'PYEOF2'
import base64,os
data={
    "pages/builder.html":"",
    "worker/src/index.js":"",
    ".github/workflows/scraper.yml":"",
    "scraper_to_sheets.py":"",
    "assets/data/builder_data.json":"",
}
for p,b in data.items():
    os.makedirs(os.path.dirname(p) if os.path.dirname(p) else ".",exist_ok=True)
    open(p,"wb").write(base64.b64decode(b))
print("✅ OK")
PYEOF2

echo "🔧 Deploying worker..."
cd worker && npx wrangler deploy && cd ..

echo "📋 Registering commands..."
curl -s "https://purgatoire-bot.originsguild.workers.dev/register" > /dev/null

git add pages/builder.html worker/src/index.js .github/workflows/scraper.yml scraper_to_sheets.py assets/data/builder_data.json
git commit -m "feat: builder complet substats + scraper GH Actions + builds roster"
git push
echo "🚀 Done!"
echo ""
echo "⚠️  IMPORTANT — Ajoute ces secrets GitHub:"
echo "  Settings → Secrets → Actions"
echo "  GOOGLE_SHEET_ID = 1npBpU9jQXFOW_mrDiycpB1ptJzXdcZE2iJ8-r8RP8oM"
echo "  GOOGLE_SERVICE_ACCOUNT_JSON = (le JSON du compte de service)"
echo ""
echo "  Et crée l'onglet Builds dans le Sheet avec:"
echo "  date | pseudo | char_slug | nom_build | build_data"
